1279	    let mut trap: bool;
1280	
1281	    // PORT NOTE: `startfunc:` is the entry point that (re)sets `trap`.
1282	    'startfunc: loop {
1283	        // C: startfunc: trap = L->hookmask;
1284	        trap = state.hook_mask() != 0;
1285	
1286	        // PORT NOTE: `returning:` is the re-entry after a Lua call returns.
1287	        // Re-enters 'returning without resetting trap.
1288	        'returning: loop {
1289	            // C: cl = ci_func(ci); k = cl->p->k; pc = ci->u.l.savedpc;
1290	            let cl = match state.ci_lua_closure(ci) {
1291	                Some(c) => c,
1292	                None => {
1293	                    return Err(LuaError::runtime(format_args!(
1294	                        "internal: execute called on non-Lua frame"
1295	                    )));
1296	                }
1297	            };
1298	            // pc is an index into proto.code (u32)
1299	            let mut pc: u32 = state.ci_savedpc(ci);
1300	
1301	            // C: if (l_unlikely(trap)) trap = luaG_tracecall(L);
1302	            if trap {
1303	                trap = state.trace_call(ci)?;
1304	            }
1305	            // C: base = ci->func.p + 1;
1306	            let mut base: StackIdx = state.ci_base(ci);
1307	
1308	            // ── Main dispatch loop ──────────────────────────────────────────
1309	            // C: for (;;) { Instruction i; vmfetch(); vmdispatch(GET_OPCODE(i)) {...} }
1310	            'dispatch: loop {
1311	                // C: vmfetch() — handle hooks, then fetch+advance pc
1312	                if trap {
1313	                    // C: trap = luaG_traceexec(L, pc); updatebase(ci);
1314	                    trap = state.trace_exec(ci, pc)?;
1315	                    base = state.ci_base(ci); // updatebase
1316	                }
1317	                let i: Instruction = state.proto_code(&cl, pc);
1318	                pc += 1;
1319	
1320	                debug_assert!(base == state.ci_base(ci));
1321	
1322	                // C: vmdispatch(GET_OPCODE(i))
1323	                match i.opcode() {
1324	                    // ── OP_MOVE ──────────────────────────────────────────────
1325	                    // C: StkId ra = RA(i); setobjs2s(L, ra, RB(i));
1326	                    OpCode::Move => {
1327	                        let ra = base + i.arg_a();
1328	                        let rb = base + i.arg_b();
1329	                        let v = state.get_at(rb).clone();
1330	                        state.set_at(ra, v);
1331	                    }
1332	                    // ── OP_LOADI ─────────────────────────────────────────────
1333	                    // C: lua_Integer b = GETARG_sBx(i); setivalue(s2v(ra), b);
1334	                    OpCode::LoadI => {
1335	                        let ra = base + i.arg_a();
1336	                        let b = i.arg_s_bx() as i64;
1337	                        state.set_at(ra, LuaValue::Int(b));
1338	                    }
1339	                    // ── OP_LOADF ─────────────────────────────────────────────
1340	                    // C: int b = GETARG_sBx(i); setfltvalue(s2v(ra), cast_num(b));
1341	                    OpCode::LoadF => {
1342	                        let ra = base + i.arg_a();
1343	                        let b = i.arg_s_bx() as f64;
1344	                        state.set_at(ra, LuaValue::Float(b));
1345	                    }
1346	                    // ── OP_LOADK ─────────────────────────────────────────────
1347	                    // C: TValue *rb = k + GETARG_Bx(i); setobj2s(L, ra, rb);
1348	                    OpCode::LoadK => {
1349	                        let ra = base + i.arg_a();
1350	                        let k_idx = i.arg_bx() as usize;
1351	                        let v = state.proto_const(&cl, k_idx).clone();
1352	                        state.set_at(ra, v);
