pub fn intern_str(&mut self, bytes: &[u8]) -> Result<GcRef<LuaString>, LuaError> {
    if let Some(existing) = self.global().interned_lt.get(bytes) {
        return Ok(existing.clone());
    }
    let _local = crate::string::new(self, bytes)?;
